import { createApi, fetchBaseQuery } from '@reduxjs/toolkit/query/react';

export const api = createApi({
  reducerPath: 'api',
  baseQuery: fetchBaseQuery({ baseUrl: '/api' }),
  tagTypes: ['User', 'Post'],
  endpoints: (build) => ({
    getUser: build.query<User, string>({
      query: (id) => `users/${id}`,
      providesTags: (_, __, id) => [{ type: 'User', id }]
    }),
    updateUser: build.mutation<User, { id: string; data: Partial<User> }>({
      query: ({ id, data }) => ({ url: `users/${id}`, method: 'PATCH', body: data }),
      invalidatesTags: (_, __, { id }) => [{ type: 'User', id }]
    })
  })
});

export const { useGetUserQuery, useUpdateUserMutation } = api;

import { createContext, useContext, useState, ReactNode } from 'react';

const TabsCtx = createContext<{ value: string; onChange: (v: string) => void } | null>(null);

export function Tabs({ value: controlledValue, onChange: controlledOnChange, defaultValue, children }: {
  value?: string; onChange?: (v: string) => void; defaultValue?: string; children: ReactNode;
}) {
  const [uncontrolledValue, setUncontrolledValue] = useState(defaultValue ?? '');
  const value = controlledValue ?? uncontrolledValue;
  const onChange = controlledOnChange ?? setUncontrolledValue;
  return <TabsCtx.Provider value={{ value, onChange }}>{children}</TabsCtx.Provider>;
}

export function Tab({ value, children }: { value: string; children: ReactNode }) {
  const ctx = useContext(TabsCtx)!;
  const active = ctx.value === value;
  return (
    <button onClick={() => ctx.onChange(value)} aria-selected={active} className={active ? 'active' : ''}>
      {children}
    </button>
  );
}

