  dsn: '...',
  beforeSend(event, hint) {
    const error = hint.originalException as Error;
    if (error?.message?.includes('NetworkError')) {
      event.fingerprint = ['network-error', String(event.contexts?.network?.url ?? 'unknown')];
    }
    return event;
  }
});

