import { useEffect } from 'react';

function useShortcut(key: string, handler: () => void, deps: unknown[] = []) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      const [mod, k] = key.split('+');
      const needsMod = mod === 'cmd' || mod === 'ctrl';
      const actualKey = needsMod ? k : mod;
      if (needsMod && !(e.metaKey || e.ctrlKey)) return;
      if (e.key.toLowerCase() !== actualKey.toLowerCase()) return;
      if (document.activeElement instanceof HTMLInputElement || document.activeElement instanceof HTMLTextAreaElement) return;
      e.preventDefault();
      handler();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [key, ...deps]);  // eslint-disable-line
}

