type Event = { type: 'click'; x: number; y: number } | { type: 'key'; key: string };

function isClick(e: Event): e is Extract<Event, { type: 'click' }> {
  return e.type === 'click';
}

function handle(e: Event) {
  if (isClick(e)) {
    console.log(e.x, e.y);  // narrowed
  } else {
    console.log(e.key);  // narrowed to key event
