}

function CDNImage({ src, width, alt }: { src: string; width: number; alt: string }) {
  const cf = `https://cdn.example.com/cdn-cgi/image/width=${width},format=auto/${src}`;
  return <img src={cf} srcSet={`${cf} ${width}w, https://cdn.example.com/cdn-cgi/image/width=${width * 2},format=auto/${src} ${width * 2}w`} alt={alt} loading="lazy" />;
}

